import{_ as e,o as t,c as o,a4 as r}from"./chunks/framework.EG5hAXdg.js";const p=JSON.parse('{"title":"About data","description":"This page gives on overview of dat management in HUNT Cloud.","frontmatter":{"title":"About data","category":"HUNT Cloud","permalink":"/administer-science/start-here/data","outline":0,"description":"This page gives on overview of dat management in HUNT Cloud."},"headers":[],"relativePath":"administer-science/start-here/data.md","filePath":"administer-science/start-here/data.md"}'),s={name:"administer-science/start-here/data.md"};function i(n,a,d,l,c,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="about-data" tabindex="-1">About data <a class="header-anchor" href="#about-data" aria-label="Permalink to &quot;About data&quot;">​</a></h1><p><strong>Data is the precious raw material of data-driven sciences. We should take good care of it and make it shine.</strong></p><nav class="table-of-contents"><ul><li><a href="#data-care">Data care</a></li><li><a href="#data-storage">Data storage</a></li><li><a href="#data-backup">Data backup</a></li><li><a href="#data-transfers">Data transfers</a></li><li><a href="#data-organization">Data organization</a></li></ul></nav><h3 id="data-care" tabindex="-1">Data care <a class="header-anchor" href="#data-care" aria-label="Permalink to &quot;Data care&quot;">​</a></h3><p>Most labs in HUNT Cloud work with sensitive data. Usually, a key success factor for our labs is to get hold of and activate as much data as possible in their projects, and to enable as much brain-power as possible to analyze the data. This may include recruiting lab users from a broad set of scientific fields and backgrounds.</p><p>We recommend that you as a lab administrator establish routines to talk with your lab users about the responsibilities they take on when working with sensitive data. For example for personal sensitive data science, that there is a human behind every number, and that such donations needs to be handled with care and respect to maintain the trust from both study participants and the broader research community.</p><h3 id="data-storage" tabindex="-1">Data storage <a class="header-anchor" href="#data-storage" aria-label="Permalink to &quot;Data storage&quot;">​</a></h3><p>By default, the home machine in your lab have three storage volumes that are reachable for all of your team:</p><ul><li><p><strong>Work volume.</strong> This is where you run your experiments. Place your scripts and code and do your work here. The directories for Workbench, licensed software (Matlab, Stata) and database directories are also stored here. Data saved here can be restored for 30 days.</p></li><li><p><strong>Archive volume</strong>. This is where you store your files that don&#39;t change that much, for example your data and analysis results. Data saved here can be restored for 30 days.</p></li><li><p><strong>Scratch volume</strong>. Scratch is designed for temporary data that gets generated when you run your scripts and analysis. This volume do -not- hold backup/restore.</p></li></ul><h3 id="data-backup" tabindex="-1">Data backup <a class="header-anchor" href="#data-backup" aria-label="Permalink to &quot;Data backup&quot;">​</a></h3><p>Both work and archive holds nightly backups, that we call restore, for 30 days. This means that you are able to restore data yourself in cases of accidental deletions and accidental overwrites. &#39;</p><p>Keep in mind that the restore function occupy a full duplicate copy of your data when you plan for your storage sizes, and additional space if you change the data over a 30 days period. To illustrate, you will need at least 2TB of storage if you plan to store 1 TB of research data.</p><p>You can turn off the restore function if you don&#39;t need the additional safety measure.</p><h3 id="data-transfers" tabindex="-1">Data transfers <a class="header-anchor" href="#data-transfers" aria-label="Permalink to &quot;Data transfers&quot;">​</a></h3><p>You lab users have several ways to get data in and out of your lab, among others:</p><ul><li><p><strong>Direct uploads from lab users</strong>. By default, lab users will be able to move small files between their local computer by &quot;drag-and-drop&quot; in their Workbench. This is intended for code and summary statistics and other day-to-day operations of non-sensitive data.</p></li><li><p><strong>External transfers of sensitive data in an our of HUNT Cloud</strong>. We have a dedicated service for sensitive data transports that we call &quot;External kista&quot;. This is aimed at hospitals and data producing facilities, and follows strict security protocols, e.g. compliance with the Norwegian &quot;Helsenorm&quot;.</p></li><li><p><strong>Internal transfers between labs</strong>. We have a dedicated service for data transports between lab environments that we call &quot;Internal kista&quot;. This is to ensure that transfers between lab environments inside HUNT Cloud is documented and controlled.</p></li></ul><p>Both external and internal kistas are ordered in our administer science service desk and require signature from either lab leaders or data space leaders before activation.</p><p>If needed, we are more than happy to assist in dialogues with your data sources to describe security controls of the kista services.</p><h3 id="data-organization" tabindex="-1">Data organization <a class="header-anchor" href="#data-organization" aria-label="Permalink to &quot;Data organization&quot;">​</a></h3><p>Regardless of how well-intentioned the initial planning of your lab may be, data organization often becomes chaotic over time. Duplicate data copies may become a significant cost-driver over time, and it might be difficult to find what you are looking for.</p><p>We recommend that one in your lab users take on the role of &quot;data administrator&quot; with the responsibility to maintain oversight and control, to guide your lab users towards the intended structure, and to clean up redundant data when necessary.</p>',21)])])}const f=e(s,[["render",i]]);export{p as __pageData,f as default};
